proof:
-- By contradiction, assume that $5 \mid \sum_{k=0}^{n} \binom{2n+1}{2k+1} \cdot 2^{3k}$.
by_contra h_contra
have h_mod : (∑ k ∈ Finset.range (n + 1), (Nat.choose (2 * n + 1) (2 * k + 1)) * 2 ^ (3 * k)) % 5 = 0 := by
  grind +splitImp;
-- Let's consider the sum $\sum_{k=0}^{n} \binom{2n+1}{2k+1} \cdot 3^k$ modulo 5.
have h_sum_mod : (∑ k ∈ Finset.range (n + 1), Nat.choose (2 * n + 1) (2 * k + 1) * 3 ^ k) % 5 ≠ 0 := by
  -- Consider the expression $(1 + \sqrt{3})^{2n+1} = A + B\sqrt{3}$ where $A$ and $B$ are integers.
  set A := ∑ k ∈ Finset.range (n + 1), Nat.choose (2 * n + 1) (2 * k) * 3 ^ k
  set B := ∑ k ∈ Finset.range (n + 1), Nat.choose (2 * n + 1) (2 * k + 1) * 3 ^ k
  have h_expr : (1 + Real.sqrt 3) ^ (2 * n + 1) = A + B * Real.sqrt 3 ∧ (1 - Real.sqrt 3) ^ (2 * n + 1) = A - B * Real.sqrt 3 := by
    have h_binom : ∀ (x : ℝ), (1 + x)^(2 * n + 1) = ∑ k ∈ Finset.range (n + 1), (Nat.choose (2 * n + 1) (2 * k)) * x^(2 * k) + ∑ k ∈ Finset.range (n + 1), (Nat.choose (2 * n + 1) (2 * k + 1)) * x^(2 * k + 1) := by
      intro x
      have h_binom : (1 + x)^(2 * n + 1) = ∑ k ∈ Finset.range (2 * n + 2), (Nat.choose (2 * n + 1) k) * x^k := by
        simp +decide [ add_comm, add_pow, mul_comm ];
        ring;
      have h_split : Finset.range (2 * n + 2) = Finset.image (fun k => 2 * k) (Finset.range (n + 1)) ∪ Finset.image (fun k => 2 * k + 1) (Finset.range (n + 1)) := by
        ext k
        simp [Finset.mem_range, Finset.mem_image];
        exact ⟨ fun h => by rcases Nat.even_or_odd' k with ⟨ k, rfl | rfl ⟩ <;> [ left; right ] <;> exact ⟨ k, by linarith, rfl ⟩, fun h => by rcases h with ( ⟨ k, hk, rfl ⟩ | ⟨ k, hk, rfl ⟩ ) <;> linarith ⟩;
      rw [ h_binom, h_split, Finset.sum_union ] <;> norm_num [ Finset.disjoint_right ];
      intros; omega;
    simp +zetaDelta at *;
    convert And.intro ( h_binom ( Real.sqrt 3 ) ) ( h_binom ( -Real.sqrt 3 ) ) using 2 <;> norm_num [ pow_add, pow_mul ] ; ring;
    · simp +decide only [Finset.sum_mul, mul_assoc, mul_left_comm];
      ac_rfl;
    · simpa only [ ← mul_assoc, Finset.sum_mul _ _ _ ] using by ring;
  -- Then $A^2 - 3B^2 = ((1 + \sqrt{3})(1 - \sqrt{3}))^{2n+1} = (-2)^{2n+1} = -2^{2n+1}$.
  have h_identity : (A : ℤ)^2 - 3 * (B : ℤ)^2 = -2^(2 * n + 1) := by
    have h_identity : ((A : ℝ) + B * Real.sqrt 3) * ((A : ℝ) - B * Real.sqrt 3) = (-2 : ℝ) ^ (2 * n + 1) := by
      rw [ ← h_expr.1, ← h_expr.2 ] ; rw [ ← mul_pow ] ; ring ; norm_num;
      ring;
    convert h_identity using 1 ; ring ; norm_num;
    norm_cast;
  -- If $5 \mid B$, then $A^2 \equiv -2^{2n+1} \pmod{5}$.
  by_cases hB : 5 ∣ B
  have hA_mod : (A : ℤ)^2 % 5 = 2 ∨ (A : ℤ)^2 % 5 = 3 := by
    have hA_mod : (A : ℤ)^2 % 5 = (-2^(2 * n + 1)) % 5 := by
      norm_num [ ← h_identity, Int.emod_eq_emod_iff_emod_sub_eq_zero ];
      exact dvd_mul_of_dvd_right ( dvd_pow ( Int.natCast_dvd_natCast.mpr hB ) two_ne_zero ) _;
    rw [ hA_mod ];
    rw [ ← Nat.mod_add_div n 4 ] ; norm_num [ pow_add, pow_mul, Nat.mul_mod, Nat.pow_mod ] ; have := Nat.mod_lt n four_pos; interval_cases n % 4 <;> norm_num;
    · rw [ neg_eq_neg_one_mul, Int.mul_emod ] ; norm_cast ; norm_num [ Nat.mul_mod, Nat.pow_mod ] ;
      decide +revert;
    · induction n / 4 <;> norm_num [ pow_succ, Int.mul_emod, Int.sub_emod ] at * ; omega;
    · rw [ neg_eq_neg_one_mul, Int.mul_emod ] ; norm_cast ; norm_num [ Nat.mul_mod, Nat.pow_mod ] ;
      decide +revert;
    · rw [ neg_eq_neg_one_mul, Int.mul_emod ] ; norm_cast ; norm_num [ Nat.mul_mod, Nat.pow_mod ] ;
      decide;
  · norm_cast at hA_mod; rw [ Nat.pow_mod ] at hA_mod; have := Nat.mod_lt A ( by decide : 5 > 0 ) ; interval_cases A % 5 <;> contradiction;
  · exact fun h => hB <| Nat.dvd_of_mod_eq_zero h;
norm_num [ Nat.pow_mul, Nat.mul_mod, Nat.pow_mod, Finset.sum_nat_mod ] at * ; aesop

